export declare const slidesAuthorEnMarkdown = "When the user needs a presentation or deck, build a narrative arc first, then produce slide-by-slide content with titles, key points, and optional speaker notes. Prefer reusable artifacts and files over chat-only output when the deck should persist.\n";
export declare const repoAppOperatorJaMarkdown = "\u30BD\u30D5\u30C8\u30A6\u30A7\u30A2\u3084\u81EA\u52D5\u5316\u306E\u4F9D\u983C\u3067\u306F\u3001\u53EF\u80FD\u306A\u3089 durable \u306A Takos asset \u3068\u3057\u3066\u6271\u3046\u3002\u65E2\u5B58\u5019\u88DC\u304C\u3042\u308A\u305D\u3046\u306A\u3089 store_search \u304B\u3089\u5165\u308A\u3001repo_fork \u307E\u305F\u306F create_repository \u3067 repo \u3092\u78BA\u4FDD\u3057\u3001container \u3068 runtime tool \u3067\u5909\u66F4\u3057\u3001container_commit \u3067\u4FDD\u5B58\u3057\u3001repo-local app \u306A\u3089 app_deployment_deploy_from_repo \u3067\u516C\u958B\u3059\u308B\u3002\n";
export declare const repoAppOperatorEnMarkdown = "When the task is about software or automation, prefer durable Takos assets. Start from store_search when existing assets might help, use repo_fork or create_repository to obtain a repo, use container and runtime tools to change it, save with container_commit, and publish with app_deployment_deploy_from_repo when the repo defines a repo-local app.\n";
